const inp = $input.item.json;
const body = inp.body || inp;
const question = (body.question || body.idea || body.topic || body.message || '').toString().trim();
if (!question) {
  return [{ json: { ok: false, skip: true, reason: 'Missing question/idea/topic in request body' } }];
}
const sessionId = `INC-${Date.now()}`;
const context = (body.context || '').toString().trim();
return [{ json: { ok: true, skip: false, sessionId, question, context } }];

const base = $('normalize_input').first().json;
const webRaw = $('search_web').first().json || {};
const ragRaw = $('search_rag').first().json || {};

const webResults = Array.isArray(webRaw.results) ? webRaw.results.slice(0, 5) : [];
const webContext = webResults.map((r, i) => `[${i+1}] ${r.title || ''}: ${r.url || ''}`).join('\n') || 'No web results';

const ragDocs = ragRaw.documents ? ragRaw.documents[0] || [] : [];
const ragDistances = ragRaw.distances ? ragRaw.distances[0] || [] : [];
const ragContext = ragDocs.slice(0, 5).map((d, i) => `[RAG-${i+1}] (dist: ${ragDistances[i]?.toFixed(3) || '?'}): ${typeof d === 'string' ? d.slice(0, 400) : ''}`).join('\n') || 'No RAG results';

return [{ json: { ...base, webContext, ragContext, webCount: webResults.length, ragCount: ragDocs.length } }];

const base = $('merge_context').first().json;
const getReply = (nodeName) => {
  try {
    const r = $(nodeName).first().json;
    return r.choices?.[0]?.message?.content || r.error || 'No response from ' + nodeName;
  } catch(e) { return 'Error: ' + e.message; }
};
const entrepreneurVote = getReply('expert_entrepreneur');
const techVote = getReply('expert_tech');
const strategyVote = getReply('expert_strategy');
return [{ json: { ...base, entrepreneurVote, techVote, strategyVote } }];

const base = $('collect_votes').first().json;
const chairRaw = $input.item.json;
const decision = chairRaw.choices?.[0]?.message?.content || 'No decision generated';
const now = new Date();
const filename = `${base.sessionId}_innovation.md`;
const filepath = `/app/logs/council_sessions/${filename}`;

const report = [
  '# Innovation Council Session (Agent Forest)',
  '',
  `**Session ID:** ${base.sessionId}`,
  `**Date:** ${now.toISOString()}`,
  `**Idea/Question:** ${base.question}`,
  `**Web Sources:** ${base.webCount} | **RAG Sources:** ${base.ragCount}`,
  '',
  '## Expert Votes',
  '',
  '### Entrepreneur Expert (Feasibility & Market)',
  base.entrepreneurVote,
  '',
  '### Tech Expert (Technical Maturity)',
  base.techVote,
  '',
  '### Strategy Expert (ROI & Vision 2030)',
  base.strategyVote,
  '',
  '## Chair Final Decision',
  decision
].join('\n');

const b64 = Buffer.from(report, 'utf8').toString('base64');
return [{
  json: { sessionId: base.sessionId, filepath, question: base.question, decision, webCount: base.webCount, ragCount: base.ragCount },
  binary: { reportData: { data: b64, mimeType: 'text/markdown', fileName: filename } }
}];

const inp = $input.item.json || {};
const fail = $('normalize_input').first().json || {};
if (fail.skip === true) {
  return [{ json: { status: 'rejected', council: 'innovation', message: fail.reason } }];
}
const built = $('build_session_report').first().json || {};
return [{ json: {
  status: 'success',
  council: 'innovation',
  sessionId: built.sessionId || 'unknown',
  question: built.question || '',
  decision: built.decision || '',
  sources: { web: built.webCount || 0, rag: built.ragCount || 0 },
  reportPath: built.filepath || ''
} }];
